import pandas as pd

data = [{'Exchange': 'New York Stock Exchange'}, {'Exchange': 'NASDAQ'}, {'Exchange': 'Hong Kong Stock Exchange'}, {'Exchange': 'Shanghai Stock Exchange'}, {'Exchange': 'Tokyo Stock Exchange'}, {'Exchange': 'Euronext'}, {'Exchange': 'Shenzhen Stock Exchange'}, {'Exchange': 'Toronto Stock Exchange'}, {'Exchange': 'National Stock Exchange of India'}, {'Exchange': 'Frankfurt Stock Exchange'}, {'Exchange': 'Korea Exchange'}, {'Exchange': 'SIX Swiss Exchange'}, {'Exchange': 'Taiwan Stock Exchange'}, {'Exchange': 'Johannesburg Stock Exchange'}]

df = pd.DataFrame(data)

def exchange_to_index(exchange):
    if exchange == 'Tokyo Stock Exchange':
        return 'N225'
    elif exchange == 'Hong Kong Stock Exchange':
        return 'HSI'
    elif exchange == 'Shanghai Stock Exchange':
        return '000001.SS'
    elif exchange == 'Shenzhen Stock Exchange':
        return '399001.SZ'
    elif exchange == 'Korea Exchange':
        return 'KS11'
    elif exchange == 'Taiwan Stock Exchange':
        return 'TWII'
    elif exchange == 'National Stock Exchange of India':
        return 'NSEI'
    else:
        return None

df['Index'] = df['Exchange'].apply(exchange_to_index)

asia_indices = df[df['Index'].notna()]['Index'].tolist()

print(asia_indices)
